#include <stdio.h>
#include <stdbool.h>
#include "riscv_nn_convolution.h"
#include "test_util.h"
#ifdef PF_COUNTER
#include "nds_pfcounter.h"
#endif
#ifdef ENA_VERIFY_CMSIS_NN_WRAPPER
#include "convert_between_andes_nn_and_cmsis_nn.h"
#endif

int test(char* fname_src1,
         char* fname_src2,
         char* fname_bias,
         char* fname_scale,
         char* fname_shift,
         char* fname_golden,
         uint16_t in_tensor_dim_x,
         uint16_t in_tensor_dim_y,
         uint16_t in_tensor_ch,
         uint16_t in_tensor_batch,
         uint16_t out_tensor_ch,
         uint16_t pad_x,
         uint16_t pad_y,
         uint16_t stride_x,
         uint16_t stride_y,
         int32_t out_offset,
         int32_t in_offset,
         int32_t act_min,
         int32_t act_max,
         uint16_t out_tensor_dim_x,
         uint16_t out_tensor_dim_y,
         bool is_bias_null)
{
    {
        char bias_usage[32];
        if (is_bias_null == true)
        {
            strcpy(bias_usage, "NULL");
        }
        else
        {
            strcpy(bias_usage, "NON-NULL");
        }

        dump_param("in_tensor_dim_x=%" PRIu16 ";in_tensor_dim_y=%" PRIu16
            ";in_tensor_ch=%" PRIu16 ";in_tensor_batch=%" PRIu16
            ";out_tensor_ch=%" PRIu16 ";pad_x=%" PRIu16 ";pad_y=%" PRIu16
            ";stride_x=%" PRIu16 ";stride_y=%" PRIu16 ";out_offset=%#" PRIx32
            ";in_offset=%#" PRIx32 ";act_min=%#" PRIx32 ";act_max=%#" PRIx32
            ";out_tensor_dim_x=%" PRIu16 ";out_tensor_dim_y=%" PRIu16
            ";bias=%s", in_tensor_dim_x, in_tensor_dim_y, in_tensor_ch,
            in_tensor_batch, out_tensor_ch, pad_x, pad_y, stride_x, stride_y,
            out_offset, in_offset, act_min, act_max, out_tensor_dim_x,
            out_tensor_dim_y, bias_usage);
    }

    uint32_t src1_len = (uint32_t)in_tensor_batch * in_tensor_ch * in_tensor_dim_x * in_tensor_dim_y;
    uint32_t src2_len = (uint32_t) out_tensor_ch * in_tensor_ch;
    uint32_t buf_len = riscv_nn_conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_get_buffer_size(in_tensor_dim_x, in_tensor_dim_y, in_tensor_ch, out_tensor_ch, pad_x, pad_y, stride_x, stride_y, out_tensor_dim_x, out_tensor_dim_y);
    // uint32_t buf_len  = riscv_nn_conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_get_buffer_size(in_tensor_ch);
    uint32_t out_len  = (uint32_t) in_tensor_batch * out_tensor_ch * out_tensor_dim_x * out_tensor_dim_y;

    FILE *fptr_src1, *fptr_src2, *fptr_bias, *fptr_scale, *fptr_shift, *fptr_golden;
    //backup originally malloced starting address for later memory releasing
    void *src1_ori, *src2_ori, *out_ori, *in_tmp_buf_ori, *bias_ori, *output_shift_ori, *output_scale_ori, *golden_ori;

    int8_t *src1 = (int8_t*)test_malloc(sizeof(int8_t) * src1_len, "src1", &src1_ori);
    int8_t *src2 = (int8_t*)test_malloc(sizeof(int8_t) * src2_len, "src2", &src2_ori);
    int32_t *bias = NULL;
    if (!is_bias_null)
        bias = (int32_t*)test_malloc(sizeof(int32_t) * out_tensor_ch, "bias", &bias_ori);
    int32_t *output_shift = (int32_t*)test_malloc(sizeof(int32_t) * out_tensor_ch, "output_shift", &output_shift_ori);
    int32_t *output_scale = (int32_t*)test_malloc(sizeof(int32_t) * out_tensor_ch, "output_scale", &output_scale_ori);
    int8_t *output = (int8_t*)test_malloc(sizeof(int8_t) * out_len, "output", &out_ori);
    int8_t *golden = (int8_t*)test_malloc(sizeof(int8_t) * out_len, "golden", &golden_ori);
    int16_t *in_tmp_buf = (int16_t*)test_malloc(buf_len, "in_tmp_buf", &in_tmp_buf_ori);

    test_Fopen(fname_src1, "rb", &fptr_src1);
    test_Fopen(fname_src2, "rb", &fptr_src2);
    if (!is_bias_null)
        test_Fopen(fname_bias, "rb", &fptr_bias);
    test_Fopen(fname_scale, "rb", &fptr_scale);
    test_Fopen(fname_shift, "rb", &fptr_shift);
    test_Fread(src1, sizeof(*src1), src1_len, fptr_src1, "src1");
    test_Fread(src2, sizeof(*src2), src2_len, fptr_src2, "src2");
    if (!is_bias_null)
        test_Fread(bias, sizeof(*bias), out_tensor_ch, fptr_bias, "bias");
    test_Fread(output_scale, sizeof(*output_scale), out_tensor_ch, fptr_scale, "output_scale");
    test_Fread(output_shift, sizeof(*output_shift), out_tensor_ch, fptr_shift, "output_shift");
    process_after_reading_input_data();

#ifdef ENA_RUN_TWICE
    riscv_nn_conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any(src1, in_tensor_dim_x,
        in_tensor_dim_y, in_tensor_ch, in_tensor_batch, src2, out_tensor_ch,
        pad_x, pad_y, stride_x, stride_y, bias, output, output_shift,
        output_scale, out_offset, in_offset, act_min, act_max, out_tensor_dim_x,
        out_tensor_dim_y, in_tmp_buf);
#endif

    process_before_perf_measuring();
#ifdef PF_COUNTER
    startPFM;
#endif
    riscv_nn_conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any(src1, in_tensor_dim_x,
        in_tensor_dim_y, in_tensor_ch, in_tensor_batch, src2, out_tensor_ch,
        pad_x, pad_y, stride_x, stride_y, bias, output, output_shift,
        output_scale, out_offset, in_offset, act_min, act_max, out_tensor_dim_x,
        out_tensor_dim_y, in_tmp_buf);
#ifdef PF_COUNTER
    stopPFM;
    readResult();
#endif

#if ENA_DUMP_GOLDEN
    test_Fopen(fname_golden, "wb+", &fptr_golden);
    fwrite(output, sizeof(*golden), out_len, fptr_golden);
    uint32_t retStatus = NDS_SUCCESS;
#else
    test_Fopen(fname_golden, "rb", &fptr_golden);
    test_Fread(golden, sizeof(*golden), out_len, fptr_golden, "golden");
    uint32_t retStatus = verify_buffer(output, golden, out_len, sizeof(*output), 0);
#endif

    test_free(&src1_ori);
    test_free(&src2_ori);
    if (!is_bias_null)
        test_free(&bias_ori);
    test_free(&output_shift_ori);
    test_free(&output_scale_ori);
    test_free(&out_ori);
    test_free(&golden_ori);
    test_free(&in_tmp_buf_ori);
    fclose(fptr_src1);
    fclose(fptr_src2);
    if (!is_bias_null)
        fclose(fptr_bias);
    fclose(fptr_scale);
    fclose(fptr_shift);
    fclose(fptr_golden);

    return retStatus;
}

int main (void)
{
    enable_fs_and_vs();
    uint16_t in_tensor_dim_x, in_tensor_dim_y, in_tensor_ch, in_tensor_batch, out_tensor_ch,
    pad_x, pad_y, stride_x, stride_y,
    out_tensor_dim_x, out_tensor_dim_y;
    int32_t out_offset, in_offset, act_min, act_max;
    uint32_t retStatus=NDS_SUCCESS;
    bool is_bias_null;

    pad_x = 0;
    pad_y = 0;
    out_offset = 5;
    in_offset = 3;
    act_min = 0xffffff81;
    act_max = 0x0000007e;

#if !ENA_MEASURE_PERF
    //test-1
    in_tensor_batch = 3;
    stride_x = 1;
    stride_y = 1;
    in_tensor_dim_x = 11;
    in_tensor_dim_y = 9;
    in_tensor_ch = 2055;
    out_tensor_ch = 5;
    out_tensor_dim_x = 11;
    out_tensor_dim_y = 9;
    is_bias_null = false;
    retStatus |= test("8b_in1.bin", "8b_in2.bin", "32b_in1.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_scale.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_shift.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_golden.bin", in_tensor_dim_x,
        in_tensor_dim_y, in_tensor_ch, in_tensor_batch, out_tensor_ch, pad_x,
        pad_y, stride_x, stride_y, out_offset, in_offset, act_min, act_max,
        out_tensor_dim_x, out_tensor_dim_y, is_bias_null);

    //test-2
    in_tensor_batch = 1;
    stride_x = 1;
    stride_y = 1;
    in_tensor_dim_x = 7;
    in_tensor_dim_y = 5;
    in_tensor_ch = 2055;
    out_tensor_ch = 7;
    out_tensor_dim_x = 7;
    out_tensor_dim_y = 5;
    is_bias_null = true;
    retStatus |= test("8b_in1.bin", "8b_in2.bin", "32b_in1.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_scale2.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_shift2.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_golden2.bin", in_tensor_dim_x,
        in_tensor_dim_y, in_tensor_ch, in_tensor_batch, out_tensor_ch, pad_x,
        pad_y, stride_x, stride_y, out_offset, in_offset, act_min, act_max,
        out_tensor_dim_x, out_tensor_dim_y, is_bias_null);

    //test-4
    in_tensor_batch = 2;
    stride_x = 3;
    stride_y = 2;
    in_tensor_dim_x = 11;
    in_tensor_dim_y = 9;
    in_tensor_ch = 7;
    out_tensor_ch = 7;
    out_tensor_dim_x = 4;
    out_tensor_dim_y = 5;
    is_bias_null = false;
    retStatus |= test("8b_in1.bin", "8b_in2.bin", "32b_in1.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_scale4.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_shift4.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_golden4.bin", in_tensor_dim_x,
        in_tensor_dim_y, in_tensor_ch, in_tensor_batch, out_tensor_ch, pad_x,
        pad_y, stride_x, stride_y, out_offset, in_offset, act_min, act_max,
        out_tensor_dim_x, out_tensor_dim_y, is_bias_null);

    //test-5
    in_tensor_batch = 1;
    stride_x = 2;
    stride_y = 3;
    in_tensor_dim_x = 9;
    in_tensor_dim_y = 7;
    in_tensor_ch = 1031;
    out_tensor_ch = 5;
    out_tensor_dim_x = 5;
    out_tensor_dim_y = 3;
    is_bias_null = true;
    retStatus |= test("8b_in1.bin", "8b_in2.bin", "32b_in1.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_scale5.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_shift5.bin",
        "conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_golden5.bin", in_tensor_dim_x,
        in_tensor_dim_y, in_tensor_ch, in_tensor_batch, out_tensor_ch, pad_x,
        pad_y, stride_x, stride_y, out_offset, in_offset, act_min, act_max,
        out_tensor_dim_x, out_tensor_dim_y, is_bias_null);

    //test-6 (for tiling-original path)
    in_tensor_batch = 1;
    stride_x = 3;
    stride_y = 2;
    in_tensor_dim_x = 56;
